"use client";

import * as React from "react";
import { Switch as BaseSwitch } from "@base-ui/react/switch";
import { cn } from "@/lib/utils";

/**
 * Liquid-glass Switch — Base UI's Switch (a11y, keyboard) with a glass bead that
 * slides across a translucent track. Behavior is Base UI's; the glass is the skin.
 */
function GlassSwitch({ className, ...props }: React.ComponentProps<typeof BaseSwitch.Root>) {
  return (
    <BaseSwitch.Root
      className={cn(
        "group relative inline-flex h-6 w-11 shrink-0 cursor-pointer items-center rounded-full p-0.5 outline-none transition-colors",
        "bg-white/15 ring-1 ring-white/15 data-[checked]:bg-white/30",
        "focus-visible:ring-2 focus-visible:ring-white/50 data-[disabled]:cursor-not-allowed data-[disabled]:opacity-50",
        className,
      )}
      {...props}
    >
      <BaseSwitch.Thumb
        className={cn(
          "size-5 rounded-full bg-gradient-to-b from-white to-white/85 transition-transform",
          "shadow-[inset_0_1px_1px_rgb(255_255_255/70%),0_1px_3px_rgb(0_0_0/35%)]",
          "data-[checked]:translate-x-5",
        )}
      />
    </BaseSwitch.Root>
  );
}

export { GlassSwitch };
